		nconf.get('plugins:active').forEach((id) => {
			pluginMap[id] = pluginMap[id] || {};
			pluginMap[id].active = true;
		});
	}

	const pluginArray = Object.values(pluginMap);

	pluginArray.sort((a, b) => {
		if (a.name > b.name) {
			return 1;
		} else if (a.name < b.name) {
			return -1;
		}
		return 0;
	});

